import React, { useState, useMemo, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { SearchIcon, LocationIcon, StarIcon, CameraIcon, MusicIcon, FlowerIcon, ChefHatIcon } from '../components/icons';

interface Service {
  id: number;
  name: string;
  category: string;
  price: number;
  rating: number;
  image: string;
  images?: string[];
  vendorName?: string;
  vendorEmail?: string;
  vendorPhone?: string;
  description?: string;
}

const categories = ['All', 'Photography', 'Videography', 'Floristry', 'Venues', 'Beauty', 'Entertainment', 'Cake & Sweets', 'Planning'];

const Search: React.FC = () => {
  const location = useLocation();
  const [category, setCategory] = useState('All');
  const [minPrice, setMinPrice] = useState('');
  const [maxPrice, setMaxPrice] = useState('');
  const [minRating, setMinRating] = useState(0);
  const [keyword, setKeyword] = useState('');
  const [services, setServices] = useState<Service[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Extract category from URL parameters when component loads
  useEffect(() => {
    const urlParams = new URLSearchParams(location.search);
    const categoryParam = urlParams.get('category');
    if (categoryParam) {
      setCategory(categoryParam);
    }
  }, [location.search]);

  // Fetch services from API
  useEffect(() => {
    const fetchServices = async () => {
      try {
        setLoading(true);
        setError(null);
        
        const params = new URLSearchParams();
        if (category !== 'All') params.append('category', category);
        if (minPrice) params.append('minPrice', minPrice);
        if (maxPrice) params.append('maxPrice', maxPrice);
        if (minRating) params.append('minRating', minRating.toString());
        if (keyword) params.append('keyword', keyword);
        
        const response = await fetch(`http://localhost:5000/api/services?${params}`);
        if (!response.ok) {
          throw new Error('Failed to fetch services');
        }
        
        const data = await response.json();
        
        // Process services to ensure proper image handling
        const processedServices = data.map((service: any) => ({
          ...service,
          image: service.images && service.images.length > 0 
            ? service.images[0] 
            : 'https://via.placeholder.com/200?text=No+Image'
        }));
        
        setServices(processedServices);
      } catch (err) {
        console.error('Error fetching services:', err);
        setError('Failed to load services. Please try again.');
        setServices([]);
      } finally {
        setLoading(false);
      }
    };

    fetchServices();
  }, [category, minPrice, maxPrice, minRating, keyword]);

  const filteredServices = services;

  return (
    <div className="container mx-auto px-4 py-8">
      <h1 className="text-2xl font-bold text-primary-600 mb-4">
        {category !== 'All' ? `${category} Services` : 'Search Services'}
      </h1>
      {category !== 'All' && (
        <div className="mb-4 p-3 bg-blue-100 border border-blue-300 rounded-lg">
          <p className="text-blue-800">
            Showing services in category: <strong>{category}</strong>
            <button 
              onClick={() => setCategory('All')} 
              className="ml-2 text-blue-600 underline hover:text-blue-800"
            >
              Clear filter
            </button>
          </p>
        </div>
      )}

      {/* Filters */}
      <div className="glass rounded-lg p-4 mb-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {/* Keyword */}
        <div>
          <label className="block text-sm font-medium text-primary-700 mb-1">Keyword</label>
          <input
            type="text"
            value={keyword}
            onChange={(e) => setKeyword(e.target.value)}
            className="w-full border border-accentNeutral rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-secondary-500"
            placeholder="e.g. photographer"
          />
        </div>

        {/* Category */}
        <div>
          <label className="block text-sm font-medium text-primary-700 mb-1">Service Category</label>
          <select
            value={category}
                        onChange={(e) => setCategory(e.target.value)}
            className="w-full border border-accentNeutral rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-secondary-500"
          >
            {categories.map((cat) => (
              <option key={cat} value={cat}>
                {cat}
              </option>
            ))}
          </select>
        </div>

        {/* Price Range */}
        <div className="flex space-x-2">
          <div className="w-1/2">
            <label className="block text-sm font-medium text-primary-700 mb-1">Min Price</label>
            <input
              type="number"
              value={minPrice}
              onChange={(e) => setMinPrice(e.target.value)}
              className="w-full border border-accentNeutral rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-secondary-500"
              placeholder="0"
            />
          </div>
          <div className="w-1/2">
            <label className="block text-sm font-medium text-primary-700 mb-1">Max Price</label>
            <input
              type="number"
              value={maxPrice}
              onChange={(e) => setMaxPrice(e.target.value)}
              className="w-full border border-accentNeutral rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-secondary-500"
              placeholder="5000"
            />
          </div>
        </div>

        {/* Rating */}
        <div>
          <label className="block text-sm font-medium text-primary-700 mb-1">Min Rating</label>
          <select
            value={minRating}
            onChange={(e) => setMinRating(Number(e.target.value))}
            className="w-full border border-accentNeutral rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-secondary-500"
          >
            {[0, 3, 3.5, 4, 4.5, 5].map((r) => (
              <option key={r} value={r}>
                {r === 0 ? 'Any' : `${r}+`}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* Results */}
      {loading ? (
        <div className="text-center py-8">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading services...</p>
        </div>
      ) : error ? (
        <div className="text-center py-8">
          <p className="text-red-600 mb-4">{error}</p>
          <button 
            onClick={() => window.location.reload()} 
            className="bg-purple-600 hover:bg-purple-700 text-white px-4 py-2 rounded"
          >
            Retry
          </button>
        </div>
      ) : filteredServices.length === 0 ? (
        <div className="text-center py-8">
          <p className="text-gray-600 mb-4">No services match your criteria.</p>
          <button 
            onClick={() => {
              setCategory('All');
              setMinPrice('');
              setMaxPrice('');
              setMinRating(0);
              setKeyword('');
            }}
            className="bg-purple-600 hover:bg-purple-700 text-white px-4 py-2 rounded"
          >
            Clear All Filters
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredServices.map((svc) => (
            <div key={svc.id} className="glass rounded-lg overflow-hidden hover:bg-white/15 transition-all duration-300">
              <img src={svc.image} alt={svc.name} className="w-full h-40 object-cover" />
              <div className="p-4">
                <h2 className="text-lg font-semibold text-white mb-1">{svc.name}</h2>
                <div className="flex items-center text-sm text-white/80 mb-2">
                  <LocationIcon className="icon-secondary mr-1" size={14} />
                  <span>Category: {svc.category}</span>
                </div>
                {svc.vendorName && (
                  <p className="text-sm text-white/70 mb-2">By: {svc.vendorName}</p>
                )}
                <p className="text-sm text-white/80 mb-2">Price: €{svc.price}</p>
                <div className="flex items-center text-sm text-yellow-400 mb-2">
                  <StarIcon className="icon-warning mr-1" size={14} />
                  <span>Rating: {svc.rating}</span>
                </div>
                <Link
                  to={`/service/${svc.id}`}
                  className="inline-block mt-2 bg-pink-500 hover:bg-pink-600 text-white text-sm px-4 py-2 rounded transition-all duration-300"
                >
                  View Details
                </Link>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Search;
