import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

interface WishlistItem {
  id: number;
  serviceId: number;
  serviceName: string;
  vendorName: string;
  category: string;
  price: number;
  rating: number;
  image: string;
  addedDate: string;
}

const ClientWishlist: React.FC = () => {
  const [wishlistItems, setWishlistItems] = useState<WishlistItem[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchWishlist();
  }, []);

  const fetchWishlist = async () => {
    try {
      setLoading(true);
      // Mock data for now - will be replaced with real API call
      const mockWishlist: WishlistItem[] = [
        {
          id: 1,
          serviceId: 101,
          serviceName: 'Luxury Wedding Photography',
          vendorName: 'Capture Moments Studio',
          category: 'Photography',
          price: 3000,
          rating: 4.8,
          image: 'https://via.placeholder.com/200',
          addedDate: '2024-01-10'
        },
        {
          id: 2,
          serviceId: 102,
          serviceName: 'Elegant Floral Arrangements',
          vendorName: 'Bloom & Blossom',
          category: 'Floristry',
          price: 1500,
          rating: 4.9,
          image: 'https://via.placeholder.com/200',
          addedDate: '2024-01-12'
        },
        {
          id: 3,
          serviceId: 103,
          serviceName: 'Grand Ballroom Venue',
          vendorName: 'Royal Gardens Hotel',
          category: 'Venues',
          price: 5000,
          rating: 4.7,
          image: 'https://via.placeholder.com/200',
          addedDate: '2024-01-15'
        }
      ];
      setWishlistItems(mockWishlist);
    } catch (error) {
      console.error('Failed to fetch wishlist:', error);
    } finally {
      setLoading(false);
    }
  };

  const removeFromWishlist = async (itemId: number) => {
    try {
      // API call to remove item
      setWishlistItems(wishlistItems.filter(item => item.id !== itemId));
    } catch (error) {
      console.error('Failed to remove item:', error);
    }
  };

  const getCategoryIcon = (category: string) => {
    const icons: { [key: string]: string } = {
      'Photography': '📸',
      'Videography': '🎥',
      'Floristry': '🌸',
      'Venues': '🏛️',
      'Beauty': '💄',
      'Entertainment': '🎵',
      'Cake & Sweets': '🎂',
      'Planning': '📋'
    };
    return icons[category] || '💝';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-white rounded-lg shadow-md p-6">
        <div className="flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">My Wishlist</h1>
            <p className="text-gray-600 mt-1">
              {wishlistItems.length} {wishlistItems.length === 1 ? 'item' : 'items'} saved
            </p>
          </div>
          {wishlistItems.length > 0 && (
            <button className="bg-purple-600 text-white px-4 py-2 rounded-lg hover:bg-purple-700 transition-colors">
              Share Wishlist
            </button>
          )}
        </div>
      </div>

      {/* Wishlist Items */}
      {wishlistItems.length === 0 ? (
        <div className="bg-white rounded-lg shadow-md p-12 text-center">
          <div className="text-6xl mb-4">❤️</div>
          <h3 className="text-xl font-semibold text-gray-900 mb-2">Your wishlist is empty</h3>
          <p className="text-gray-500 mb-6">
            Start adding services you love to keep track of them here.
          </p>
          <Link
            to="/categories"
            className="inline-block bg-purple-600 text-white px-6 py-3 rounded-lg hover:bg-purple-700 transition-colors"
          >
            Browse Services
          </Link>
        </div>
      ) : (
        <>
          {/* Stats Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-white rounded-lg shadow-md p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-500">Total Value</p>
                  <p className="text-xl font-bold text-gray-900">
                    €{wishlistItems.reduce((sum, item) => sum + item.price, 0).toLocaleString()}
                  </p>
                </div>
                <span className="text-2xl">💰</span>
              </div>
            </div>
            <div className="bg-white rounded-lg shadow-md p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-500">Categories</p>
                  <p className="text-xl font-bold text-gray-900">
                    {new Set(wishlistItems.map(item => item.category)).size}
                  </p>
                </div>
                <span className="text-2xl">📊</span>
              </div>
            </div>
            <div className="bg-white rounded-lg shadow-md p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-500">Avg Rating</p>
                  <p className="text-xl font-bold text-gray-900">
                    {(wishlistItems.reduce((sum, item) => sum + item.rating, 0) / wishlistItems.length).toFixed(1)}
                  </p>
                </div>
                <span className="text-2xl">⭐</span>
              </div>
            </div>
          </div>

          {/* Wishlist Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {wishlistItems.map((item) => (
              <div key={item.id} className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition-shadow">
                <div className="relative">
                  <img
                    src={item.image}
                    alt={item.serviceName}
                    className="w-full h-48 object-cover"
                  />
                  <button
                    onClick={() => removeFromWishlist(item.id)}
                    className="absolute top-2 right-2 bg-white rounded-full p-2 shadow-md hover:bg-red-50 transition-colors"
                    title="Remove from wishlist"
                  >
                    <svg className="w-5 h-5 text-red-500" fill="currentColor" viewBox="0 0 20 20">
                      <path fillRule="evenodd" d="M3.172 5.172a4 4 0 015.656 0L10 6.343l1.172-1.171a4 4 0 115.656 5.656L10 17.657l-6.828-6.829a4 4 0 010-5.656z" clipRule="evenodd" />
                    </svg>
                  </button>
                  <div className="absolute top-2 left-2 bg-white rounded-full px-3 py-1 shadow-md">
                    <span className="text-sm font-medium">
                      {getCategoryIcon(item.category)} {item.category}
                    </span>
                  </div>
                </div>

                <div className="p-4">
                  <h3 className="text-lg font-semibold text-gray-900 mb-1">
                    {item.serviceName}
                  </h3>
                  <p className="text-sm text-gray-600 mb-2">by {item.vendorName}</p>
                  
                  <div className="flex items-center justify-between mb-3">
                    <span className="text-xl font-bold text-purple-600">
                      €{item.price.toLocaleString()}
                    </span>
                    <div className="flex items-center space-x-1">
                      <span className="text-yellow-400">⭐</span>
                      <span className="text-sm text-gray-600">{item.rating}</span>
                    </div>
                  </div>

                  <div className="flex space-x-2">
                    <Link
                      to={`/service/${item.serviceId}`}
                      className="flex-1 text-center bg-purple-600 text-white py-2 rounded-lg hover:bg-purple-700 transition-colors"
                    >
                      View Details
                    </Link>
                    <button className="flex-1 text-center border border-purple-600 text-purple-600 py-2 rounded-lg hover:bg-purple-50 transition-colors">
                      Book Now
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
};

export default ClientWishlist;
