import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

const BrowseServices: React.FC = () => {
  const { t } = useTranslation();
  const [selectedCategory, setSelectedCategory] = useState('All');

  const categories = [
    'All', 'Photography', 'Videography', 'Venues', 'Catering', 
    'Floristry', 'Music & DJ', 'Beauty', 'Planning', 'Decoration'
  ];

  const services = [
    { id: 1, name: 'Premium Wedding Photography', category: 'Photography', price: 2500, rating: 4.9 },
    { id: 2, name: 'Elegant Venue Rental', category: 'Venues', price: 5000, rating: 4.8 },
    { id: 3, name: 'Gourmet Catering Service', category: 'Catering', price: 3500, rating: 4.7 },
    { id: 4, name: 'Bridal Makeup & Hair', category: 'Beauty', price: 800, rating: 4.9 },
    { id: 5, name: 'Wedding DJ & Sound', category: 'Music & DJ', price: 1200, rating: 4.6 },
    { id: 6, name: 'Floral Arrangements', category: 'Floristry', price: 1800, rating: 4.8 }
  ];

  const filteredServices = selectedCategory === 'All' 
    ? services 
    : services.filter(service => service.category === selectedCategory);

  return (
    <div className="min-h-screen bg-gradient-to-b from-[#f6d8d8] to-[#5a9be7] py-12">
      <div className="container mx-auto px-4">
        <div className="max-w-6xl mx-auto">
          {/* Header */}
          <div className="text-center mb-12">
            <h1 className="font-playfair text-4xl md:text-5xl font-bold text-white mb-4">
              Browse Wedding Services
            </h1>
            <p className="text-xl text-white/90">
              Discover amazing vendors for your special day
            </p>
          </div>

          {/* Category Filter */}
          <div className="bg-white/10 backdrop-blur-md rounded-xl p-6 mb-8">
            <h3 className="text-white font-semibold mb-4">Filter by Category:</h3>
            <div className="flex flex-wrap gap-2">
              {categories.map(category => (
                <button
                  key={category}
                  onClick={() => setSelectedCategory(category)}
                  className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                    selectedCategory === category
                      ? 'bg-[#d4af37] text-white'
                      : 'bg-white/20 text-white hover:bg-white/30'
                  }`}
                >
                  {category}
                </button>
              ))}
            </div>
          </div>

          {/* Services Grid */}
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredServices.map(service => (
              <div key={service.id} className="bg-white/10 backdrop-blur-md rounded-xl p-6 hover:bg-white/20 transition-all">
                <div className="h-48 bg-white/20 rounded-lg mb-4 flex items-center justify-center">
                  <span className="text-white/60">Service Image</span>
                </div>
                <h3 className="font-playfair text-xl font-semibold text-white mb-2">
                  {service.name}
                </h3>
                <p className="text-white/80 mb-2">Category: {service.category}</p>
                <p className="text-white/80 mb-2">Starting from: €{service.price}</p>
                <div className="flex items-center mb-4">
                  <span className="text-yellow-400">★</span>
                  <span className="text-white ml-1">{service.rating}</span>
                </div>
                <Link
                  to={`/service/${service.id}`}
                  className="inline-block bg-[#d4af37] hover:bg-[#b48a3b] text-white px-6 py-2 rounded-lg font-semibold transition-colors"
                >
                  View Details
                </Link>
              </div>
            ))}
          </div>

          {/* Call to Action */}
          <div className="text-center mt-12">
            <div className="bg-white/10 backdrop-blur-md rounded-xl p-8">
              <h2 className="font-playfair text-2xl font-semibold text-white mb-4">
                Can't find what you're looking for?
              </h2>
              <p className="text-white/90 mb-6">
                Contact us and we'll help you find the perfect vendors for your wedding
              </p>
              <Link
                to="/help"
                className="bg-[#d4af37] hover:bg-[#b48a3b] text-white px-8 py-3 rounded-lg font-semibold transition-colors"
              >
                Get Help
              </Link>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BrowseServices;
