import React, { useMemo, useState, useEffect } from 'react';
import { Calendar, dateFnsLocalizer, Event } from 'react-big-calendar';
import { format, parse, startOfWeek, getDay } from 'date-fns';
// English locale for date-fns
import enUS from 'date-fns/locale/en-US';
import 'react-big-calendar/lib/css/react-big-calendar.css';
import { useVendor } from '../../context/VendorContext';

const locales = {
  'en-US': enUS,
};

const localizer = dateFnsLocalizer({
  format,
  parse,
  startOfWeek: () => startOfWeek(new Date(), { weekStartsOn: 0 }), // Sunday start
  getDay,
  locales,
});

interface CalendarEvent extends Event {
  resource: any;
}

const VendorCalendar: React.FC = () => {
  // Read availability settings from LocalStorage and make them updateable
  const getWorkingSettings = () => {
    const storedDays = localStorage.getItem('vendorWorkingDays');
    const storedHours = localStorage.getItem('vendorWorkingHours');
    return {
      days: storedDays ? JSON.parse(storedDays) as number[] : [0,1,2,3,4,5,6],
      hours: storedHours ? JSON.parse(storedHours) as {start:string,end:string} : { start: '00:00', end: '23:59' },
    };
  };

  const [{ days: workingDays, hours: workingHours }, setWorking] = useState(getWorkingSettings());

  // Listen for settings changes
  useEffect(() => {
    const handler = () => setWorking(getWorkingSettings());
    window.addEventListener('vendorWorkingChanged', handler);
    return () => window.removeEventListener('vendorWorkingChanged', handler);
  }, []);

  const { start, end } = workingHours;

  // Convert HH:MM to today's date
  const today = new Date();
  const [startHour, startMinute] = start.split(':').map(Number);
  const [endHour, endMinute] = end.split(':').map(Number);
  const minTime = new Date(today.getFullYear(), today.getMonth(), today.getDate(), startHour, startMinute);
  const maxTime = new Date(today.getFullYear(), today.getMonth(), today.getDate(), endHour, endMinute);

  const { availability, addBlockedSlot, removeAvailability, services } = useVendor();
  const [serviceFilter, setServiceFilter] = useState<'all' | number>('all');

  // Convert periods to calendar events
  const events: CalendarEvent[] = useMemo(() => {
    return availability
      .filter(slot => (serviceFilter === 'all' || slot.serviceId === serviceFilter || slot.serviceId === null))
      .map((slot) => ({
      id: slot.id,
      title: slot.type === 'BOOKED' ? 'Booked' : 'Blocked',
      start: new Date(slot.start),
      end: new Date(slot.end),
      allDay: true,
      resource: slot,
    }));
  }, [availability, serviceFilter]);

  // Custom style for colors
  const eventPropGetter = (event: CalendarEvent) => {
    const bg = event.resource.type === 'BOOKED' ? '#F87171' : '#9CA3AF'; // Red or gray
    return { style: { backgroundColor: bg, borderRadius: '4px', color: '#fff' } };
  };

  // When selecting a BLOCKED event, it can be removed
  const handleSelectEvent = (event: CalendarEvent) => {
    if (event.resource.type === 'BLOCKED') {
      if (window.confirm('Unblock this period?')) {
        removeAvailability(event.resource.id as number);
      }
    }
  };

  // When selecting an empty period, the vendor can block it
  const handleSelectSlot = (slotInfo: { start: Date; end: Date }) => {
    // Allow selection only on working days and within working hours
    if (!workingDays.includes(slotInfo.start.getDay())) {
      alert('Selected day is outside working days');
      return;
    }
        const slotStartMinutes = slotInfo.start.getHours()*60 + slotInfo.start.getMinutes();
    const slotEndMinutes = slotInfo.end.getHours()*60 + slotInfo.end.getMinutes();

    // Check if full day is selected (month view) where it starts and ends at midnight
    const isFullDay = slotStartMinutes === 0 && slotEndMinutes === 0;

    const workStartMinutes = startHour*60 + startMinute;
    const workEndMinutes = endHour*60 + endMinute;
    if (!isFullDay && (slotStartMinutes < workStartMinutes || slotEndMinutes > workEndMinutes)) {
      alert('Selected time is outside working hours');
      return;
    }

    if (window.confirm('Do you want to block this period?')) {
      addBlockedSlot({
        vendorId: availability[0]?.vendorId || 1,
        serviceId: null,
        start: slotInfo.start.toISOString(),
        end: slotInfo.end.toISOString(),
      });
    }
  };

  return (
    <>
      <div className="mb-4 flex gap-2 items-center">
        <label className="text-sm">Service:</label>
        <select
          value={serviceFilter}
          onChange={(e) => setServiceFilter(e.target.value === 'all' ? 'all' : Number(e.target.value))}
          className="border border-gray-300 rounded px-2 py-1 text-sm"
        >
          <option value="all">All</option>
          {services.filter(s => s.isActive).map((s) => (
            <option key={s.id} value={s.id}>{s.name}</option>
          ))}
        </select>
      </div>

      <Calendar
      culture="en-US"
      localizer={localizer}
      events={events}
      startAccessor="start"
      endAccessor="end"
      style={{ height: 600 }}
      selectable
      min={minTime}
      max={maxTime}
      onSelectEvent={handleSelectEvent}
      onSelectSlot={handleSelectSlot}
      eventPropGetter={eventPropGetter}
      views={['month', 'week', 'day']}
    />
    </>
  );
};

export default VendorCalendar;
